        case "column":
            VStack(alignment: columnAlignment, spacing: tokens.spacing(node["spacing"] as? String ?? "normal")) {
                childViews(node["children"] as? [RuntimeJSON] ?? [], context: context)
            }
            .padding(tokens.spacing(node["padding"] as? String ?? "none"))
        case "row":
            HStack(alignment: rowAlignment, spacing: tokens.spacing(node["spacing"] as? String ?? "normal")) {
                childViews(node["children"] as? [RuntimeJSON] ?? [], context: context)
            }
            .padding(tokens.spacing(node["padding"] as? String ?? "none"))
        case "text":
            Text(node["bind"] is String ? resolve(node["bind"] as! String).text : node["value"] as? String ?? "")
                .font(tokens.font(node["role"] as? String ?? "body"))
                .foregroundStyle(tokens.color(node["color"] as? String ?? "textPrimary"))
