    @ViewBuilder private func childViews(_ children: [RuntimeJSON], context: RuntimeContext) -> some View {
        ForEach(Array(children.enumerated()), id: \.offset) { _, child in
            RuntimeNodeView(node: child, screen: screen, screenName: screenName, bundle: bundle, state: state, router: router, actions: actions, context: context)
        }
