    private var columnAlignment: HorizontalAlignment {
        switch node["align"] as? String { case "start": return .leading; case "end": return .trailing; default: return .center }
    }
    private var rowAlignment: VerticalAlignment {
        switch node["align"] as? String { case "start": return .top; case "end": return .bottom; default: return .center }
    }

    private var runtimeButton: some View {
        let role = node["role"] as? String ?? "primary"
        return Button { perform(node["action"] as? String ?? "") } label: {
            Text(node["label"] as? String ?? "")
                .font(tokens.font("body"))
                .frame(minWidth: tokens.size("buttonMinWidth"), minHeight: tokens.size("controlHeight"))
                .padding(.horizontal, tokens.spacing("normal"))
