        .buttonStyle(.plain)
        .foregroundStyle(role == "primary" ? tokens.color("onPrimary") : tokens.color("primary"))
        .background(role == "primary" ? tokens.color("primary") : tokens.color("fieldBackground"), in: RoundedRectangle(cornerRadius: tokens.radius("large")))
        .overlay(role == "secondary" ? RoundedRectangle(cornerRadius: tokens.radius("large")).stroke(tokens.color("border"), lineWidth: tokens.size("borderWidth")) : nil)
