        .font(tokens.font("body"))
        .foregroundStyle(tokens.color("textPrimary"))
        .padding(.horizontal, tokens.spacing("normal"))
        .frame(height: tokens.size("controlHeight"))
        .background(tokens.color("fieldBackground"), in: RoundedRectangle(cornerRadius: tokens.radius("normal")))
        .overlay(RoundedRectangle(cornerRadius: tokens.radius("normal")).stroke(tokens.color("border"), lineWidth: tokens.size("borderWidth")))
        .keyboardType(keyboardType)
    }

    private var keyboardType: UIKeyboardType {
        switch node["keyboard"] as? String { case "email": return .emailAddress; case "number": return .numberPad; case "phone": return .phonePad; default: return .default }
    }

    private var runtimeList: some View {
        let name = node["bind"] as? String ?? ""
        let items = state.lists[name] ?? []
        let template = node["itemTemplate"] as? [RuntimeJSON] ?? []
        return VStack(alignment: .leading, spacing: 0) {
            ForEach(Array(items.enumerated()), id: \.offset) { index, item in
                childViews(template, context: RuntimeContext(props: context.props, actionProps: context.actionProps, item: item))
                if index < items.count - 1 { Divider().padding(.leading, tokens.spacing("normal")) }
            }
        }
        .background(tokens.color("listRowBackground"), in: RoundedRectangle(cornerRadius: tokens.radius("normal")))
        .clipShape(RoundedRectangle(cornerRadius: tokens.radius("normal")))
    }

    private var runtimeListRow: some View {
        Button { perform(node["action"] as? String ?? "") } label: {
            HStack(spacing: tokens.spacing("normal")) {
                VStack(alignment: .leading, spacing: tokens.spacing("tight")) {
                    Text(boundText(literal: "title", binding: "titleBind")).font(tokens.font("body")).foregroundStyle(tokens.color("textPrimary"))
                    if node["subtitle"] != nil || node["subtitleBind"] != nil {
                        Text(boundText(literal: "subtitle", binding: "subtitleBind")).font(tokens.font("caption")).foregroundStyle(tokens.color("textSecondary"))
                    }
                }
                Spacer()
                Image(systemName: "chevron.right").foregroundStyle(tokens.color("chevron"))
            }
            .padding(.horizontal, tokens.spacing("normal"))
            .padding(.vertical, tokens.spacing("tight"))
            .frame(maxWidth: .infinity, minHeight: tokens.size("listRowMinHeight"), alignment: .leading)
        }
        .buttonStyle(.plain)
        .background(tokens.color("listRowBackground"))
    }

    private func boundText(literal: String, binding: String) -> String {
        if let name = node[binding] as? String { return resolve(name).text }
        return node[literal] as? String ?? ""
    }

    @ViewBuilder private var runtimeComponent: some View {
        if let name = node["name"] as? String, let component = bundle.component(name) {
            let next = componentContext(component)
            RuntimeNodeGroup(nodes: component["body"] as? [RuntimeJSON] ?? [], screen: screen, screenName: screenName, bundle: bundle, state: state, router: router, actions: actions, context: next)
        }
    }

    private func componentContext(_ component: RuntimeJSON) -> RuntimeContext {
        let supplied = node["props"] as? RuntimeJSON ?? [:]
        var next = RuntimeContext(actionProps: context.actionProps, item: context.item)
        for definition in component["props"] as? [RuntimeJSON] ?? [] {
            guard let name = definition["name"] as? String, let type = definition["type"] as? String else { continue }
            let value = supplied[name]
            if type == "action" { next.actionProps[name] = value as? String ?? "" }
            else if let string = value as? String, string.hasPrefix("item.") || state.values[string] != nil || context.props[string] != nil {
                next.props[name] = resolve(string)
            } else { next.props[name] = RuntimeScalar(value) }
        }
        return next
    }
}

struct RuntimeTokens {
    let values: RuntimeJSON
    init(_ values: RuntimeJSON) { self.values = values }
    func number(_ group: String, _ name: String) -> CGFloat {
        CGFloat(((values[group] as? RuntimeJSON)?[name] as? NSNumber)?.doubleValue ?? 0)
    }
    func spacing(_ name: String) -> CGFloat { number("spacing", name) }
    func radius(_ name: String) -> CGFloat { number("radius", name) }
    func size(_ name: String) -> CGFloat { number("size", name) }
    func contentWidth(_ name: String?) -> CGFloat? {
        guard let name, name != "fill" else { return nil }
        return size("content" + name.prefix(1).uppercased() + name.dropFirst())
    }
    func color(_ name: String) -> Color {
        Color(hex: ((values["color"] as? RuntimeJSON)?[name] as? String) ?? "#000000")
    }
    func font(_ name: String) -> Font {
        let definition = (values["typography"] as? RuntimeJSON)?[name] as? RuntimeJSON ?? [:]
        let size = (definition["size"] as? NSNumber)?.doubleValue ?? 16
        let weight: Font.Weight
        switch definition["weight"] as? String { case "bold": weight = .bold; case "semibold": weight = .semibold; default: weight = .regular }
        return .system(size: size, weight: weight)
    }
}

extension Color {
    init(hex: String) {
        let raw = hex.trimmingCharacters(in: CharacterSet.alphanumerics.inverted)
        var value: UInt64 = 0
        Scanner(string: raw).scanHexInt64(&value)
        let red = Double((value >> 16) & 0xff) / 255
        let green = Double((value >> 8) & 0xff) / 255
        let blue = Double(value & 0xff) / 255
        self.init(red: red, green: green, blue: blue)
    }
}
